#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>
#include <type_traits>

// Type-safe conversion functions with explicit specializations only
// No generic fallback to prevent unintended implicit conversions

// For float: identity
__device__ __forceinline__ float convert_to_float(float val) {
    return val;
}

// For half: explicit conversion
__device__ __forceinline__ float convert_to_float(half val) {
    return __half2float(val);
}

// For double: explicit narrowing (matches original static_cast behavior)
__device__ __forceinline__ float convert_to_float(double val) {
    return static_cast<float>(val);
}

// Convert from float to target type with explicit specializations
__device__ __forceinline__ float convert_from_float(float val) {
    return val;
}

__device__ __forceinline__ half convert_from_float_half(float val) {
    return __float2half_rn(val);
}

__device__ __forceinline__ double convert_from_float_double(float val) {
    return static_cast<double>(val);
}

template<typename T>
__global__ void layernorm_fused_kernel(
    const T* __restrict__ input,
    T* __restrict__ output,
    const T* __restrict__ gamma,
    const T* __restrict__ beta,
    const float eps,
    const int num_elements,
    const int feature_size
) {
    extern __shared__ float shared_mem[];

    int batch_idx = blockIdx.x;
    int tid = threadIdx.x;

    const T* batch_input = input + batch_idx * feature_size;
    T* batch_output = output + batch_idx * feature_size;

    // Phase 1: Compute mean using parallel reduction
    float sum = 0.0f;
    for (int i = tid; i < feature_size; i += blockDim.x) {
        // Type-safe conversion based on T
        if constexpr (std::is_same<T, float>::value) {
            sum += batch_input[i];
        } else if constexpr (std::is_same<T, half>::value) {
            sum += convert_to_float(batch_input[i]);
        } else if constexpr (std::is_same<T, double>::value) {
            sum += convert_to_float(batch_input[i]);
        } else {
            // Compile-time error for unsupported types
            static_assert(std::is_same<T, float>::value || 
                         std::is_same<T, half>::value || 
                         std::is_same<T, double>::value, 
                         "Unsupported type in layernorm_fused_kernel");
        }
    }

    shared_mem[tid] = sum;
    __syncthreads();

    // Parallel reduction for mean
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            shared_mem[tid] += shared_mem[tid + stride];
        }
        __syncthreads();
    }

    float mean = shared_mem[0] / feature_size;
    __syncthreads();

    // Phase 2: Compute variance using parallel reduction
    float var_sum = 0.0f;
    for (int i = tid; i < feature_size; i += blockDim.x) {
        float diff;
        if constexpr (std::is_same<T, float>::value) {
            diff = batch_input[i] - mean;
        } else if constexpr (std::is_same<T, half>::value) {
            diff = convert_to_float(batch_input[i]) - mean;
        } else {
            diff = convert_to_float(batch_input[i]) - mean;
        }
        var_sum += diff * diff;
    }

    shared_mem[tid] = var_sum;
    __syncthreads();

    // Parallel reduction for variance
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            shared_mem[tid] += shared_mem[tid + stride];
        }
        __syncthreads();
    }

    float variance = shared_mem[0] / feature_size;
    float inv_std = rsqrtf(variance + eps);

    // Phase 3: Apply normalization with gamma and beta
    for (int i = tid; i < feature_size; i += blockDim.x) {
        float normalized;
        if constexpr (std::is_same<T, float>::value) {
            normalized = (batch_input[i] - mean) * inv_std;
        } else if constexpr (std::is_same<T, half>::value) {
            normalized = (convert_to_float(batch_input[i]) - mean) * inv_std;
        } else {
            normalized = (convert_to_float(batch_input[i]) - mean) * inv_std;
        }

        float gamma_val, beta_val;
        if constexpr (std::is_same<T, float>::value) {
            gamma_val = gamma[i % num_elements];
            beta_val = beta[i % num_elements];
        } else if constexpr (std::is_same<T, half>::value) {
            gamma_val = convert_to_float(gamma[i % num_elements]);
            beta_val = convert_to_float(beta[i % num_elements]);
        } else {
            gamma_val = convert_to_float(gamma[i % num_elements]);
            beta_val = convert_to_float(beta[i % num_elements]);
        }

        normalized = normalized * gamma_val + beta_val;

        // Type-safe conversion back
        if constexpr (std::is_same<T, float>::value) {
            batch_output[i] = normalized;
        } else if constexpr (std::is_same<T, half>::value) {
            batch_output[i] = convert_from_float_half(normalized);
        } else {
            batch_output[i] = convert_from_float_double(normalized);
        }
    }
}

torch::Tensor layernorm_fused_cuda(
    torch::Tensor input,
    torch::Tensor gamma,
    torch::Tensor beta,
    float eps
) {
    auto sizes = input.sizes();
    int batch_size = 1;
